'use client'
import { useState, useEffect } from 'react'
import { useSalesStore } from '@/store/useSalesStore'
import { BanknotesIcon, ArrowTrendingUpIcon, ArrowTrendingDownIcon } from '@heroicons/react/24/outline'

export default function SalesReportPage() {
  const { 
    getSalesForLast30Days, 
    getGrossIncome, 
    getNetIncome, 
    getDailySalesData 
  } = useSalesStore()
  
  const [grossIncome, setGrossIncome] = useState(0)
  const [netIncome, setNetIncome] = useState(0)
  const [dailyData, setDailyData] = useState<Array<{ date: string; total: number; count: number }>>([])
  const [totalTransactions, setTotalTransactions] = useState(0)

  useEffect(() => {
    const sales = getSalesForLast30Days()
    const endDate = new Date()
    const startDate = new Date()
    startDate.setDate(startDate.getDate() - 30)
    
    setGrossIncome(getGrossIncome(startDate, endDate))
    setNetIncome(getNetIncome(startDate, endDate))
    setDailyData(getDailySalesData(30))
    setTotalTransactions(sales.length)
  }, [])

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-PH', { 
      style: 'currency', 
      currency: 'PHP' 
    }).format(amount)
  }

  const maxDailyTotal = Math.max(...dailyData.map(d => d.total), 1)

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-900">Sales Report</h1>
        <div className="text-sm text-gray-500">
          Last 30 days • {totalTransactions} transactions
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        <div className="bg-white rounded-xl border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-blue-100 rounded-lg">
                <BanknotesIcon className="size-6 text-blue-600" />
              </div>
              <div>
                <div className="text-sm text-gray-600">Gross Income</div>
                <div className="text-2xl font-bold text-gray-900">{formatCurrency(grossIncome)}</div>
              </div>
            </div>
            <ArrowTrendingUpIcon className="size-5 text-green-500" />
          </div>
        </div>

        <div className="bg-white rounded-xl border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-green-100 rounded-lg">
                <BanknotesIcon className="size-6 text-green-600" />
              </div>
              <div>
                <div className="text-sm text-gray-600">Net Income</div>
                <div className="text-2xl font-bold text-gray-900">{formatCurrency(netIncome)}</div>
              </div>
            </div>
            <ArrowTrendingUpIcon className="size-5 text-green-500" />
          </div>
        </div>

        <div className="bg-white rounded-xl border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-purple-100 rounded-lg">
                <BanknotesIcon className="size-6 text-purple-600" />
              </div>
              <div>
                <div className="text-sm text-gray-600">Profit Margin</div>
                <div className="text-2xl font-bold text-gray-900">
                  {grossIncome > 0 ? `${((netIncome / grossIncome) * 100).toFixed(1)}%` : '0%'}
                </div>
              </div>
            </div>
            <ArrowTrendingUpIcon className="size-5 text-green-500" />
          </div>
        </div>
      </div>

      {/* Daily Sales Chart */}
      <div className="bg-white rounded-xl border border-gray-200 p-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-6">Daily Sales (Last 30 Days)</h2>
        <div className="space-y-4">
          {dailyData.map((day, index) => (
            <div key={index} className="flex items-center gap-4">
              <div className="w-16 text-sm text-gray-600">{day.date}</div>
              <div className="flex-1 bg-gray-100 rounded-full h-6 relative overflow-hidden">
                <div 
                  className="bg-blue-500 h-full rounded-full transition-all duration-300"
                  style={{ width: `${(day.total / maxDailyTotal) * 100}%` }}
                />
              </div>
              <div className="w-20 text-right">
                <div className="text-sm font-medium text-gray-900">{formatCurrency(day.total)}</div>
                <div className="text-xs text-gray-500">{day.count} sales</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Recent Transactions */}
      <div className="bg-white rounded-xl border border-gray-200 p-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-6">Recent Transactions</h2>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-gray-200">
                <th className="text-left py-3 px-4 text-gray-600 font-medium">Date</th>
                <th className="text-left py-3 px-4 text-gray-600 font-medium">Items</th>
                <th className="text-left py-3 px-4 text-gray-600 font-medium">Payment</th>
                <th className="text-right py-3 px-4 text-gray-600 font-medium">Total</th>
              </tr>
            </thead>
            <tbody>
              {getSalesForLast30Days().slice(-10).reverse().map((sale) => (
                <tr key={sale.id} className="border-b border-gray-100">
                  <td className="py-3 px-4 text-sm text-gray-900">
                    {new Date(sale.date).toLocaleDateString('en-PH', { 
                      month: 'short', 
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </td>
                  <td className="py-3 px-4 text-sm text-gray-900">
                    {sale.items.length} item{sale.items.length !== 1 ? 's' : ''}
                  </td>
                  <td className="py-3 px-4 text-sm text-gray-900 capitalize">{sale.paymentMethod}</td>
                  <td className="py-3 px-4 text-sm font-medium text-gray-900 text-right">
                    {formatCurrency(sale.total)}
                  </td>
                </tr>
              ))}
              {getSalesForLast30Days().length === 0 && (
                <tr>
                  <td className="py-8 px-4 text-center text-gray-500" colSpan={4}>
                    No sales data available
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}